import pysam
import os
import sys

def main():
    input_bam = "/tmp/coding_bench_t1-mapq_2lo3m92m/input.bam"
    output_bam = "output.bam"
    temp_bam = "temp.bam"

    # Open input BAM
    try:
        infile = pysam.AlignmentFile(input_bam, "rb")
    except Exception as e:
        print(f"Failed to open input BAM: {e}")
        sys.exit(1)

    # Create temporary BAM for unsorted filtered reads
    try:
        outfile = pysam.AlignmentFile(temp_bam, "wb", template=infile)
    except Exception as e:
        print(f"Failed to create temporary BAM: {e}")
        infile.close()
        sys.exit(1)

    # Filter reads
    try:
        for read in infile:
            if read.mapq >= 30:
                outfile.write(read)
    except Exception as e:
        print(f"Error during filtering: {e}")
        infile.close()
        outfile.close()
        sys.exit(1)
    finally:
        infile.close()
        outfile.close()

    # Sort the temporary BAM by coordinate and write to output.bam
    try:
        pysam.sort("-o", output_bam, temp_bam)
    except Exception as e:
        print(f"Failed to sort BAM: {e}")
        sys.exit(1)

    # Index the output BAM
    try:
        pysam.index(output_bam)
    except Exception as e:
        print(f"Failed to index BAM: {e}")
        sys.exit(1)

    # Remove temporary file
    try:
        os.remove(temp_bam)
    except OSError:
        pass

    print("Successfully filtered, sorted, and indexed BAM.")

if __name__ == "__main__":
    main()

import pysam
import sys

def verify():
    bam_file = "output.bam"
    try:
        bam = pysam.AlignmentFile(bam_file, "rb")
    except Exception as e:
        print(f"Cannot open {bam_file}: {e}")
        return False

    # Check that all reads have MAPQ >= 30
    low_mapq = []
    for read in bam.fetch():
        if read.mapq < 30:
            low_mapq.append((read.query_name, read.mapq))
    bam.close()

    if low_mapq:
        print(f"Found {len(low_mapq)} reads with MAPQ < 30:")
        for name, mapq in low_mapq[:5]:
            print(f"  {name}: {mapq}")
        return False

    # Check sorting: we can iterate and ensure positions are non-decreasing within each reference
    # We'll do a simple check: for each reference, the alignment positions should be increasing.
    try:
        bam = pysam.AlignmentFile(bam_file, "rb")
        prev_ref = None
        prev_pos = -1
        for read in bam.fetch():
            if bam.get_reference_name(read.reference_id) != prev_ref:
                # new reference, reset position check
                prev_ref = bam.get_reference_name(read.reference_id)
                prev_pos = -1
            if read.reference_id == -1:
                # unmapped read, skip position check
                continue
            pos = read.reference_start
            if pos < prev_pos:
                print(f"Unsorted position: read {read.query_name} at {pos} after {prev_pos} on {prev_ref}")
                bam.close()
                return False
            prev_pos = pos
        bam.close()
    except Exception as e:
        print(f"Error during sorting check: {e}")
        return False

    print("All checks passed: MAPQ >= 30 and coordinate-sorted.")
    return True

if __name__ == "__main__":
    if verify():
        sys.exit(0)
    else:
        sys.exit(1)

import pysam

def count_bam(path):
    try:
        with pysam.AlignmentFile(path, "rb") as bam:
            return sum(1 for _ in bam)
    except Exception as e:
        return f"Error: {e}"

print("input.bam:", count_bam("input.bam"))
print("output.bam:", count_bam("output.bam"))
print(".gold.bam:", count_bam(".gold.bam"))
